import { o as decks, t as db } from "../../../../../../chunks/db.js";
import { r as renderDeckToPresentation } from "../../../../../../chunks/pdf.js";
import { error } from "@sveltejs/kit";
import { and, eq } from "drizzle-orm";
//#region src/routes/api/decks/[id]/present/+server.ts
async function GET(event) {
	if (!event.locals.user) throw error(401, "Not authenticated");
	const deckId = event.params.id;
	const [deck] = await db.select({ id: decks.id }).from(decks).where(and(eq(decks.id, deckId), eq(decks.ownerId, event.locals.user.id))).limit(1);
	if (!deck) throw error(404, "Deck not found");
	const html = await renderDeckToPresentation(deckId);
	return new Response(html, { headers: { "Content-Type": "text/html; charset=utf-8" } });
}
//#endregion
export { GET };
